+fn trim_rendered_output(s: &str) -> String {
+    let mut out = String::new();
+    let mut iter = s.split('\n').peekable();
+    while let Some(line) = iter.next() {
+        out.push_str(line.trim());
+        if iter.peek().is_some() {
+            out.push('\n');
+        }
+    }
+    out
+}
